/* JSON ?쒕뱶 ?뚯씪????_schema瑜?癒몄?. ?ъ슜?먭? ?낅젰??媛믪? ?덈? 嫄대뱶由ъ? ?딄퀬,
   _schema留???긽 理쒖떊?쇰줈 媛깆떊. fresh???덈줈 異붽????ㅻ뒗 鍮?媛믪쑝濡?異붽??섍퀬,
   existing?먮쭔 ?덈뒗 ?ㅻ룄 蹂댁〈 (?? ?섏쨷??OAuth flow媛 異붽????좏겙). */
function _mergeSchemaIntoJson(p: string, freshJson: string) {
  if (!fs.existsSync(p)) {
    fs.writeFileSync(p, freshJson);
    return;
  }
  try {
    const fresh = JSON.parse(freshJson);
    const existing = JSON.parse(fs.readFileSync(p, 'utf-8') || '{}');
    /* 1) existing??紐⑤뱺 ??洹몃?濡?蹂댁〈 (OAuth ?좏겙泥섎읆 ?숈쟻?쇰줈 異붽???媛??ы븿) */
    const merged: Record<string, any> = { ...existing };
    /* 2) fresh?먮쭔 ?덈뒗 ???ㅻ뒗 鍮?媛믪쑝濡?異붽? */
    for (const k of Object.keys(fresh)) {
      if (k === '_schema') continue;
      if (!(k in merged)) merged[k] = fresh[k];
    }
    /* 3) _schema????긽 理쒖떊 fresh濡???뼱?곌린 (?ъ슜?먭? ?몄쭛?섏? ?딅뒗 硫뷀?) */
    merged['_schema'] = fresh['_schema'];
    fs.writeFileSync(p, JSON.stringify(merged, null, 2));
  } catch {
    fs.writeFileSync(p, freshJson);
  }
}

